        "조건": "smoke test가 통과해야 함"
      },
      {
        "내용": "packageName mismatch가 발생하면 먼저 package config를 확인한다."
      },
      {
        "내용": "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
      }
    ],
    "거절된_제안": [
      {
        "제안": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "제안자": "Hara",
        "결과": "거절됨"
      }
    ],
    "내부_스트레치_목표": [
      {
        "내용": "수요일 릴리스",
        "제안자": "Seoyeon",
        "상태": "내부 stretch goal일 뿐, 최종 결정 아님"
      }
    ],
    "비결정_사항": [
      {
        "내용": "README install steps를 목요일까지 가능하면 검토한다는 의견이 있었으나 owner는 배정되지 않았다."
      },
      {
        "내용": "Hara가 Minjun의 smoke 결과 공유 이후 generated tarball path를 확인하기로 했으나 정확한 deadline은 정해지지 않았다."
      }
    ],
    "리스크": [
      {
        "내용": "잘못된 tarball path는 릴리스를 지연시킬 수 있다."
      },
      {
        "내용": "README install steps가 오래된 경우 release notes가 사용자를 오도할 수 있다."
      }
    ],
    "오픈_질문": [
      {
        "내용": "최종 release approval authority는 누구인가?"
      },
      {
        "내용": "release note에 내부 수요일 stretch goal을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 후 generated tarball path를 확인한다.",
      "due": null,
      "status": "확정, 정확한 deadline 없음",
      "source_certainty": "confirmed"
    },
    {
